// Sourced knowledge base, generated by scripts/build-kb.mjs (npm run kb:build):
// supplement-drug interactions from SUPP.AI (literature-extracted) and outcome
// citations from Pillser. Loaded at startup; no network calls per request.
interface SuppAiInteraction { cui: string; name: string; aliases: string[]; evidence_count: number; url: string }
interface SuppAiSupplement { cui: string; matched_name: string; drug_interactions: SuppAiInteraction[] }
interface InteractionsDoc { source: string; source_url: string; generated_at: string; supplements: Record<string, SuppAiSupplement> }
interface OutcomeSource { title: string; url: string; study_count: number | null }
interface OutcomesDoc { source: string; source_url: string; outcomes: Record<string, OutcomeSource> }

const INTERACTIONS = interactionsData as unknown as InteractionsDoc;
