// Customized action plans: turn a stored analysis into a prioritized set of
// lifestyle interventions and an evidence-graded supplement stack, mapped from
// each out-of-range finding (Examine.com-style). Everything is wellness-framed
// and educational; it never diagnoses, treats, or tells a user to change a
// prescribed medication. Supplements the user already logs are flagged rather
// than re-recommended, and known supplement-drug interactions surface as
// cautions against the user's medication list.

// Evidence grade mirrors a familiar A–D convention:
//   A = strong/consistent human evidence   B = moderate, some good trials
//   C = limited/preliminary or mechanistic  D = mixed/weak, mostly context
export type EvidenceGrade = 'A' | 'B' | 'C' | 'D';

export const EVIDENCE_LABELS: Record<EvidenceGrade, string> = {
  A: 'Strong, consistent human evidence',
  B: 'Moderate evidence from good trials',
  C: 'Limited or preliminary evidence',
  D: 'Mixed or mechanistic evidence',
};

type InterventionCategory = 'nutrition' | 'exercise' | 'sleep' | 'stress' | 'substance' | 'other';

// A supplement in the catalog. `interacts_with` lists medication classes/genes
// (see MEDICATION_CLASSES) that warrant a caution when the user takes one.
interface SupplementRef {
  id: string;
  name: string;
  form?: string;
  typical_dose: string;
  timing?: string;
  evidence: EvidenceGrade;
  evidence_note: string;
  mechanism?: string;
  cautions?: string[];
  interacts_with?: string[];
  aliases?: string[];
}

interface InterventionRef {
  id: string;
  name: string;
  category: InterventionCategory;
  detail: string;
  evidence: EvidenceGrade;
}

interface Trigger {
  marker: string;
  direction: 'high' | 'low';
  interventions: string[];
  supplements: string[];
}

