export type ActionPriority = 'core' | 'optimize';

export interface ActionTarget {
  marker: string;
  finding: string;
  direction: 'low' | 'high' | 'ok';
  status?: string;
}

export interface ActionSource {
  name: string;
  url?: string;
  detail?: string;
}

export interface ActionPlanIntervention {
  id: string;
  name: string;
  category: InterventionCategory;
  detail: string;
  evidence: EvidenceGrade;
  priority: ActionPriority;
  targets: ActionTarget[];
  rationale: string;
}

export interface ActionPlanSupplement {
  id: string;
  name: string;
  form?: string;
  typical_dose?: string;
  timing?: string;
  dose_guidance: string;
  evidence: EvidenceGrade;
  evidence_note: string;
  mechanism?: string;
  priority: ActionPriority;
  targets: ActionTarget[];
  rationale: string;
  cautions: string[];
  already_taking: boolean;
  sources: ActionSource[];
}

export interface ActionPlan {
  analysis_id: string;
  user_id: string;
  organization_id?: string;
  generated_at: string;
  summary: string;
  interventions: ActionPlanIntervention[];
  supplements: ActionPlanSupplement[];
  cautions: string[];
  evidence_key: Record<EvidenceGrade, string>;
  sources: ActionSource[];
  disclaimer: string;
  provenance: { analysis_id: string; source_ids: string[]; engine: string };
}

const DISCLAIMER =
  'Educational wellness guidance, not medical advice. It does not diagnose or treat disease. ' +
  'Supplements are not a substitute for prescribed medication - never start, stop, or change a medication based on this plan. ' +
  'Confirm nutrient deficiencies with testing and discuss supplements and interactions with a clinician or pharmacist, especially during pregnancy or with existing conditions.';

interface FlaggedFinding {
  marker: string;
  direction: 'low' | 'high';
  finding: string;
  status?: string;
  score: number;
  sourceIds: string[];
}

const EVIDENCE_ORDER: Record<EvidenceGrade, number> = { A: 0, B: 1, C: 2, D: 3 };

export interface ActionPlanOptions {
  /** Exact dose/timing is withheld by default until a clinician-reviewed policy explicitly enables it. */
  includeSupplementDoses?: boolean;
}

export function buildActionPlan(analysis: AnalysisResult, options: ActionPlanOptions = {}): ActionPlan {
  const flagged = collectFlaggedFindings(analysis.derived_interpretations);
  const inventory = behavioralInventory(analysis);
  const takenSupplementKeys = supplementKeySet(inventory.supplements.map(s => s.name));
  const medicationNames = inventory.medications.map(m => m.name);
  const medicationClasses = classifyMedications(medicationNames);

  const interventionAgg = new Map<string, { ref: InterventionRef; targets: ActionTarget[]; topStatus: string }>();
  const supplementAgg = new Map<string, { ref: SupplementRef; targets: ActionTarget[]; topStatus: string }>();

  for (const flag of flagged) {
    const trigger = TRIGGER_INDEX.get(`${flag.marker}:${flag.direction}`);
    if (!trigger) continue;
    const target: ActionTarget = { marker: flag.marker, finding: flag.finding, direction: flag.direction, status: flag.status };
    for (const id of trigger.interventions) {
      const ref = INTERVENTIONS[id];
      if (!ref) continue;
      const entry = interventionAgg.get(id) ?? { ref, targets: [], topStatus: flag.status ?? 'watch' };
      entry.targets.push(target);
      if (rankStatus(flag.status) < rankStatus(entry.topStatus)) entry.topStatus = flag.status ?? entry.topStatus;
      interventionAgg.set(id, entry);
    }
    for (const id of trigger.supplements) {
      const ref = SUPPLEMENTS[id];
      if (!ref) continue;
      const entry = supplementAgg.get(id) ?? { ref, targets: [], topStatus: flag.status ?? 'watch' };
      entry.targets.push(target);
      if (rankStatus(flag.status) < rankStatus(entry.topStatus)) entry.topStatus = flag.status ?? entry.topStatus;
      supplementAgg.set(id, entry);
    }
  }

  const interventions = [...interventionAgg.values()]
    .map(entry => ({
      id: entry.ref.id,
      name: entry.ref.name,
      category: entry.ref.category,
      detail: entry.ref.detail,
      evidence: entry.ref.evidence,
      priority: priorityForStatus(entry.topStatus),
      targets: entry.targets,
      rationale: rationale(entry.targets),
    }))
    .sort(compareActions);

  const supplements = [...supplementAgg.values()]
    .map(entry => {
      // Literature-cited interactions from supp.ai take precedence; the hand map
      // fills drugs supp.ai has no extracted evidence for.
      const supp = suppAiInteractions(entry.ref.id, entry.ref.name, medicationNames);
      const cautions = [...(entry.ref.cautions ?? []), ...supp.cautions];
      for (const cls of entry.ref.interacts_with ?? []) {
        const med = medicationClasses.get(cls);
        if (med && !supp.matchedDrugs.has(normalizeName(med))) {
          cautions.push(`You logged ${med}: ${entry.ref.name} ${INTERACTION_TEXT[cls] ?? 'may interact'}.`);
        }
      }
      return {
        id: entry.ref.id,
        name: entry.ref.name,
        form: entry.ref.form,
        ...(options.includeSupplementDoses ? {
          typical_dose: entry.ref.typical_dose,
          timing: entry.ref.timing,
        } : {}),
        dose_guidance: options.includeSupplementDoses
          ? 'This reference range is educational and still requires review against age, pregnancy status, conditions, medications, kidney/liver function, and measured deficiency.'
          : 'Exact dose and timing are withheld by the API. Confirm need, product, dose, timing, interactions, and a retest plan with a qualified clinician or pharmacist.',
        evidence: entry.ref.evidence,
        evidence_note: entry.ref.evidence_note,
        mechanism: entry.ref.mechanism,
        priority: priorityForStatus(entry.topStatus),
        targets: entry.targets,
        rationale: rationale(entry.targets),
        cautions,
        already_taking: isAlreadyTaking(entry.ref, takenSupplementKeys),
        sources: dedupeSources([...supplementSuppAiSource(entry.ref.id), ...supp.sources, ...pillserSourcesForTargets(entry.targets)]),
      };
    })
    .sort(compareActions);

  const cautions = planCautions(inventory);
  const coreCount = interventions.filter(i => i.priority === 'core').length + supplements.filter(s => s.priority === 'core').length;
  const summary = flagged.length === 0
    ? 'No out-of-range findings to act on - your markers are within target. Keep the current routine and re-test on schedule.'
    : `${flagged.length} finding${flagged.length === 1 ? '' : 's'} outside target mapped to ${interventions.length} lifestyle change${interventions.length === 1 ? '' : 's'} and ${supplements.length} supplement${supplements.length === 1 ? '' : 's'}${coreCount ? `, ${coreCount} of them core priorities` : ''}. Start with the lifestyle changes; layer supplements where a target justifies them.`;

  return {
    analysis_id: analysis.id,
    user_id: analysis.user_id,
    organization_id: analysis.organization_id,
    generated_at: new Date().toISOString(),
    summary,
    interventions,
    supplements,
    cautions,
    evidence_key: EVIDENCE_LABELS,
    sources: [
      { name: INTERACTIONS.source, url: INTERACTIONS.source_url, detail: 'Supplement–drug interaction evidence extracted from the scientific literature.' },
      { name: OUTCOMES.source, url: OUTCOMES.source_url, detail: 'Supplement–health-outcome study counts, cited per finding.' },
    ],
    disclaimer: DISCLAIMER,
    provenance: {
      analysis_id: analysis.id,
      source_ids: analysis.source_ids ?? [],
      engine: 'health-api action_plan_engine',
    },
  };
}

function collectFlaggedFindings(derived: DerivedInterpretation[]): FlaggedFinding[] {
  const flagged: FlaggedFinding[] = [];
  for (const item of derived) {
    if (item.status !== 'needs_attention' && item.status !== 'watch') continue;
    const raw = (item.raw ?? {}) as { id?: string; direction?: string; unit_unrecognized?: boolean };
    if (raw.unit_unrecognized) continue;
    const marker = raw.id;
    const direction = raw.direction;
    if (!marker || (direction !== 'low' && direction !== 'high')) continue;
    flagged.push({
      marker,
      direction,
      finding: item.title,
      status: item.status,
      score: item.score ?? 100,
      sourceIds: item.provenance?.source_ids ?? [],
    });
  }
  // Most out-of-range first, so higher-severity targets lead the aggregation.
  return flagged.sort((a, b) => rankStatus(a.status) - rankStatus(b.status) || a.score - b.score);
}

function behavioralInventory(analysis: AnalysisResult): ReturnType<typeof analyzeBehavioral>['inventory'] {
  const entries = (analysis.normalized_observations ?? [])
    .filter(obs => obs.category === 'behavioral' && obs.raw && typeof obs.raw === 'object' && 'kind' in (obs.raw as object))
    .map(obs => obs.raw as BehavioralEntry);
  if (entries.length === 0) return { supplements: [], medications: [], notes: [] };
  return analyzeBehavioral(entries).inventory;
}

function supplementKeySet(names: string[]): Set<string> {
  const set = new Set<string>();
  for (const name of names) set.add(normalizeName(name));
  return set;
}

function isAlreadyTaking(ref: SupplementRef, takenKeys: Set<string>): boolean {
  const candidates = [ref.id, ref.name, ...(ref.aliases ?? [])].map(normalizeName);
  for (const key of takenKeys) {
    if (candidates.some(candidate => candidate && (key.includes(candidate) || candidate.includes(key)))) return true;
  }
  return false;
}

function classifyMedications(names: string[]): Map<string, string> {
  const map = new Map<string, string>();
  for (const name of names) {
    for (const { test, classes } of MEDICATION_CLASSES) {
      if (test.test(name)) {
        for (const cls of classes) if (!map.has(cls)) map.set(cls, name);
      }
    }
  }
  return map;
}

function planCautions(inventory: ReturnType<typeof analyzeBehavioral>['inventory']): string[] {
  const cautions: string[] = [];
  const flaggedMeds = inventory.medications.filter(m => m.pharmacogenes && m.pharmacogenes.length > 0);
  if (flaggedMeds.length > 0) {
    cautions.push(
      `You logged ${flaggedMeds.length} medication${flaggedMeds.length === 1 ? '' : 's'} with pharmacogenomic relevance (${flaggedMeds.map(m => m.name).join(', ')}). ` +
      'If you have genetic data, review gene-drug (CPIC) response and dosing context with a clinician or pharmacist.',
    );
  }
  return cautions;
}

function rationale(targets: ActionTarget[]): string {
  const labels = targets.map(t => `${t.direction === 'low' ? 'low' : 'high'} ${t.finding}`);
  return `Targets ${labels.join(', ')}.`;
}

function rankStatus(status?: string): number {
  if (status === 'needs_attention') return 0;
  if (status === 'watch') return 1;
  return 2;
}

function priorityForStatus(status?: string): ActionPriority {
  return status === 'needs_attention' ? 'core' : 'optimize';
}

function compareActions(
  a: { priority: ActionPriority; evidence: EvidenceGrade; targets: ActionTarget[] },
  b: { priority: ActionPriority; evidence: EvidenceGrade; targets: ActionTarget[] },
): number {
  if (a.priority !== b.priority) return a.priority === 'core' ? -1 : 1;
  if (b.targets.length !== a.targets.length) return b.targets.length - a.targets.length;
  return EVIDENCE_ORDER[a.evidence] - EVIDENCE_ORDER[b.evidence];
}

// Match a supp.ai drug interaction against the user's logged medications, and
// return cited cautions + source links for the ones they actually take.
function suppAiInteractions(supplementId: string, refName: string, medicationNames: string[]): { cautions: string[]; sources: ActionSource[]; matchedDrugs: Set<string> } {
  const data = INTERACTIONS.supplements[supplementId];
  const cautions: string[] = [];
  const sources: ActionSource[] = [];
  const matchedDrugs = new Set<string>();
  if (!data || medicationNames.length === 0) return { cautions, sources, matchedDrugs };
  for (const interaction of data.drug_interactions) {
    const med = medicationNames.find(name => aliasMatch(name, interaction.aliases));
    if (!med) continue;
    matchedDrugs.add(normalizeName(interaction.name));
    const reports = `${interaction.evidence_count} literature ${interaction.evidence_count === 1 ? 'report' : 'reports'}`;
    cautions.push(`You logged ${med}: ${refName} has a documented interaction with ${interaction.name} (${reports} via supp.ai). Review with a clinician or pharmacist.`);
    sources.push({ name: 'SUPP.AI', url: interaction.url, detail: `${refName} × ${interaction.name} interaction evidence` });
  }
  return { cautions, sources, matchedDrugs };
}

function aliasMatch(medName: string, aliases: string[]): boolean {
  const n = normalizeName(medName);
  if (n.length < 4) return false;
  return aliases.some(alias => {
    const a = normalizeName(alias);
    return a.length >= 4 && (a === n || a.includes(n) || n.includes(a));
  });
}

function supplementSuppAiSource(supplementId: string): ActionSource[] {
  const data = INTERACTIONS.supplements[supplementId];
  if (!data || data.drug_interactions.length === 0) return [];
  return [{ name: 'SUPP.AI', url: `https://supp.ai/a/${data.cui}`, detail: `${data.drug_interactions.length} drug interactions on file` }];
}

function pillserSourcesForTargets(targets: ActionTarget[]): ActionSource[] {
  const sources: ActionSource[] = [];
  const seen = new Set<string>();
  for (const target of targets) {
    const slug = MARKER_OUTCOME_SLUG[`${target.marker}:${target.direction}`];
    if (!slug || seen.has(slug)) continue;
    const outcome = OUTCOMES.outcomes[slug];
    if (!outcome) continue;
    seen.add(slug);
    sources.push({ name: 'Pillser', url: outcome.url, detail: outcome.study_count ? `${outcome.study_count} studies - ${outcome.title}` : outcome.title });
  }
  return sources;
}

function dedupeSources(sources: ActionSource[]): ActionSource[] {
  const byUrl = new Map<string, ActionSource>();
  for (const source of sources) {
    const key = source.url ?? source.name;
    if (!byUrl.has(key)) byUrl.set(key, source);
  }
  return [...byUrl.values()];
}

function normalizeName(value: string): string {
  return value.toLowerCase().trim().replace(/[^a-z0-9]+/g, '');
}
